function editRow(id) { const p = state.products.find(x => x.id === id); if (!p) return; state.editingId = id; $('editState').textContent = 'Tahrirlash: ' + id; $('sourceUrl').value = p.sourceUrl || ''; applySource(p.source || { url: p.sourceUrl, id: p.itemId, images: p.images }, { keepForm: true }); state.externalImages = sourceGallery(p.source || p); $('name').value = p.name || ''; $('nameRu').value = p.name_ru || ''; $('oldPrice').value = p.oldPrice || 0; $('priceCny').value = p.source?.priceCny || ''; $('sourcePriceUzs').value = p.sourcePriceUzs || p.source?.sourcePriceUzs || p.source?.priceUzs || ''; $('chinaDomesticFeeUzs').value = p.chinaDomesticFeeUzs || p.source?.chinaDomesticFeeUzs || 0; $('weightKg').value = p.weightKg || ''; const spec=SOURCE_SPECS[p.sourcePlatform]||sourceSpec(p.source||p); $('price').value = p.price || ''; $('minDays').value = p.deliveryMinDays || spec.min; $('maxDays').value = p.deliveryMaxDays || spec.max; $('moq').value = p.moq || 1; $('stock').value = p.source?.stock || 0; $('popularScore').value = p.popularScore || 50; $('tags').value = (p.tags || []).join(', '); $('description').value = p.description || ''; refreshPricingPreview(true); }
async function normalizeAnyImagesToStorage(urls, itemId) { const original = uniq((urls || []).map(normalizeImageUrl).filter(Boolean)).slice(0, 18); const result = await copyUrlsToStorage(original, (itemId || 'draft') + '-standard', 'Eski rasmlar qayta standartlanmoqda'); return { urls: original.map(x => result.urlMap.get(x) || x), externalImages: original, ...result }; }
async function normalizeRow(id, btn) { if (!confirm('Ushbu mahsulotning asosiy galereyasi yagona 1200×1200 px formatga qayta tayyorlansinmi?')) return; const p = state.products.find(x => x.id === id); const urls = (p?.source?.galleryImages?.length ? p.source.galleryImages : p?.source?.images?.length ? p.source.images : p?.images) || []; if (!urls.length) return toast('Qayta ishlash uchun rasm topilmadi'); setBusy(btn, true, 'Tayyorlanmoqda...'); try { const batch = await normalizeAnyImagesToStorage(urls, p?.itemId || id); const d = await api({ action: 'applyNormalizedImages', productId: id, images: batch.urls, externalImages: batch.externalImages }); copyNotice(`${d.normalized || batch.normalized || 0} ta galereya rasmi yagona standartga tayyorlandi.`, batch.failed ? 'warning' : 'success'); toast('Galereya standartlashtirildi'); await loadList(); } catch (e) { toast(e.message); copyNotice(e.message, 'error'); } finally { setBusy(btn, false, 'Rasmlarni standartlash'); } }
async function rebuildCatalogRow(id,btn){if(!confirm('Ushbu tashqi market mahsulotining alohida variant modeli barcha guruhlar bo‘yicha qayta yaratilsinmi?'))return;setBusy(btn,true,'Model yaratilmoqda...');try{const d=await api({action:'rebuildCustomerCatalog',productId:id});toast(`${d.optionGroupCount||0} guruh · ${d.skuCount||0} SKU yaratildi`);copyNotice(`Tashqi katalog modeli yangilandi: ${d.optionGroupCount||0} ta guruh va ${d.skuCount||0} ta SKU.`,d.hasVariants?'success':'warning');await loadList();}catch(e){toast(e.message);copyNotice(e.message,'error');}finally{setBusy(btn,false,'Variant modelini qayta yaratish');}}
async function archiveRow(id) { if (!confirm('Mahsulot katalogdan yashirilsinmi?')) return; try { await api({ action: 'archive', productId: id }); toast('Mahsulot arxivlandi'); await loadList(); } catch (e) { toast(e.message); } }
function decodeBase64Url(v) { const pad = '='.repeat((4 - v.length % 4) % 4), raw = atob(String(v).replace(/-/g, '+').replace(/_/g, '/') + pad), bytes = Uint8Array.from(raw, c => c.charCodeAt(0)); return new TextDecoder().decode(bytes); }
function acceptExtensionImport(){const match=location.hash.match(/(?:^#|&)(?:ommarket|om1688)=([^&]+)/);if(!match)return;try{const packet=JSON.parse(decodeBase64Url(match[1])),src=packet?.item,spec=detectSource(src?.url||'');if(!src?.url||!spec)throw new Error('Importer ma’lumoti noto‘g‘ri');history.replaceState(null,'',location.pathname+location.search);state.editingId='';$('editState').textContent='Kengaytmadan yangi qoralama';$('extensionReady').classList.add('received');$('extensionReady').innerHTML=`<i class="fa-solid fa-circle-check"></i><div><b>${esc(spec.label)} sahifasidan ma’lumot olindi</b><p>Asosiy galereya, barcha variant guruhlari va SKU kombinatsiyalarini tekshirib saqlang.</p></div>`;$('sourceUrl').value=src.url;applySource({...src,sourcePlatform:src.sourcePlatform||spec.key,sourceLabel:src.sourceLabel||spec.label,priceCurrency:src.priceCurrency||spec.currency});notice(`${spec.label} qoralamasi tayyor. Saqlashdan oldin tekshiring.`,'success');}catch(e){notice('Kengaytmadan kelgan qoralama ochilmadi: '+e.message,'error');}}
$('apiBtn').addEventListener('click', apiPreview); $('manualBtn').addEventListener('click', manual); $('saveBtn').addEventListener('click', save); $('applyVariantReviewBtn').addEventListener('click', () => applyReviewedVariants(true)); $('clearVariantReviewBtn').addEventListener('click', () => { $('reviewColors').value=''; $('reviewSizes').value=''; $('reviewExtraGroups').value=''; state.reviewLocked=true; applyReviewedVariants(true); }); ['reviewColors','reviewSizes','reviewExtraGroups'].forEach(id => $(id).addEventListener('input', () => { state.reviewLocked=true; const hint=$('variantReviewHint'); hint.className='warn'; hint.textContent='O‘zgarish bor. “Variantlarni tayyorlash” tugmasini bosing yoki katalogga saqlang.'; })); $('refreshBtn').addEventListener('click', loadList); $('loginBtn').addEventListener('click', requireAdminLogin); $('authBtn').addEventListener('click', () => auth.currentUser ? signOut(auth) : requireAdminLogin()); ['priceCny','sourcePriceUzs','chinaDomesticFeeUzs','weightKg'].forEach(id=>$(id)?.addEventListener('input',()=>refreshPricingPreview(true))); $('savePricingPolicyBtn')?.addEventListener('click',savePricingPolicy); $('repriceChinaProductsBtn')?.addEventListener('click',repriceChinaProducts); ['policyFreeWeightKg','policyExtraKgRateUzs','policyKgStep','policyRoundToUzs'].forEach(id=>$(id)?.addEventListener('input',()=>{state.chinaPricingPolicy={...state.chinaPricingPolicy,...readPricingPolicyEditor()};renderPricingPolicyEditor();})); $('policyTierRows')?.addEventListener('input',()=>{state.chinaPricingPolicy={...state.chinaPricingPolicy,...readPricingPolicyEditor()};refreshPricingPreview(true);}); $('savedGrid').addEventListener('click', e => { const edit = e.target.closest('[data-edit]'), catalog=e.target.closest('[data-catalog]'), normalize = e.target.closest('[data-normalize]'), archive = e.target.closest('[data-archive]'); if (edit) editRow(edit.dataset.edit); if (catalog) rebuildCatalogRow(catalog.dataset.catalog,catalog); if (normalize) normalizeRow(normalize.dataset.normalize, normalize); if (archive) archiveRow(archive.dataset.archive); });
onAuthStateChanged(auth, u => { $('loginBox').hidden = !!u; $('authBtn').innerHTML = u ? '<i class="fa-solid fa-right-from-bracket"></i><span>Chiqish</span>' : '<i class="fa-brands fa-google"></i><span>Kirish</span>'; if (u) loadList(); else { state.products = []; renderList(); requireAdminLogin(); } });
